 15→var connectCmd = &cobra.Command{
 16→	Use:   "connect <service>",
 17→	Short: "Connect a service (gmail, linkedin)",
 18→	Args:  cobra.ExactArgs(1),
 19→	RunE: func(cmd *cobra.Command, args []string) error {
 20→		id := args[0]
 21→		switch id {
 22→		case "gmail":
 23→			return connectGmail()
 24→		case "linkedin":
 25→			return connectLinkedIn()
 26→		default:
 27→			fmt.Printf("Unknown service: %s\n", id)
 28→			fmt.Println("Available: gmail, linkedin")
 29→			return fmt.Errorf("unknown service: %s", id)
 30→		}
 31→	},
 32→}
