  1→package connector
  2→
  3→import (
  4→	"fmt"
  5→
  6→	"gopkg.in/yaml.v3"
  7→)
  8→
  9→// YAMLConnector is the parsed representation of a connector YAML file.
 10→type YAMLConnector struct {
 11→	SchemaVersion int          `yaml:"schema_version"`
 12→	ID            string       `yaml:"id"`
 13→	Name          string       `yaml:"name"`
 14→	Type          string       `yaml:"type"`
 15→	Tier          int          `yaml:"tier"`
 16→	Required      bool         `yaml:"required"`
 17→	Description   string       `yaml:"description"`
 18→	Icon          string       `yaml:"icon"`
 19→	Auth          AuthConfig   `yaml:"auth"`
 20→	Credentials   CredConfig   `yaml:"credentials"`
 21→	Verify        VerifyConfig `yaml:"verify"`
 22→	Proxy         ProxyConfig  `yaml:"proxy"`
 23→}
 24→
 25→// AuthConfig describes how to authenticate with the service.
 26→type AuthConfig struct {
 27→	Method       string            `yaml:"method"` // oauth2, api_key, basic, webhook
 28→	AuthorizeURL string            `yaml:"authorize_url"`
 29→	TokenURL     string            `yaml:"token_url"`
 30→	Scopes       []string          `yaml:"scopes"`
 31→	AuthStyle    string            `yaml:"auth_style"`   // in_params, in_header
 32→	ExtraParams  map[string]string `yaml:"extra_params"`
 33→	// api_key fields
 34→	Header     string `yaml:"header"`
 35→	QueryParam string `yaml:"query_param"`
 36→	EnvVar     string `yaml:"env_var"`
 37→	// basic auth fields
 38→	UsernameVar string `yaml:"username_var"`
 39→	PasswordVar string `yaml:"password_var"`
 40→	// webhook fields
 41→	URLVar string `yaml:"url_var"`
 42→}
 43→
 44→// CredConfig describes where credentials come from.
 45→type CredConfig struct {
 46→	Source          string `yaml:"source"` // env, bundled, google_json, file, prompt
 47→	ClientIDVar     string `yaml:"client_id_var"`
 48→	ClientSecretVar string `yaml:"client_secret_var"`
 49→}
 50→
 51→// VerifyConfig describes the connection verification call.
 52→type VerifyConfig struct {
 53→	URL           string            `yaml:"url"`
 54→	Method        string            `yaml:"method"`
 55→	Headers       map[string]string `yaml:"headers"`
 56→	AccountFields []string          `yaml:"account_fields"`
 57→	AccountLabel  string            `yaml:"account_label"`
 58→}
 59→
 60→// ProxyConfig describes how to call the service's API.
 61→type ProxyConfig struct {
 62→	BaseURL    string `yaml:"base_url"`
 63→	AuthHeader string `yaml:"auth_header"`
 64→}
 65→
 66→// ParseYAML parses and validates a connector YAML definition.
 67→func ParseYAML(data []byte) (*YAMLConnector, error) {
 68→	var def YAMLConnector
 69→	if err := yaml.Unmarshal(data, &def); err != nil {
 70→		return nil, fmt.Errorf("parsing YAML: %w", err)
 71→	}
 72→	if err := validateDef(&def); err != nil {
 73→		return nil, err
 74→	}
 75→	// Defaults
 76→	if def.Tier == 0 {
 77→		def.Tier = 2
 78→	}
 79→	if def.Verify.Method == "" {
 80→		def.Verify.Method = "GET"
 81→	}
 82→	return &def, nil
 83→}
 84→
 85→func validateDef(d *YAMLConnector) error {
 86→	if d.SchemaVersion != 1 {
 87→		return fmt.Errorf("connector definition has unsupported schema_version: %d (expected 1)", d.SchemaVersion)
 88→	}
 89→	if d.ID == "" {
 90→		return fmt.Errorf("connector definition missing required field: id")
 91→	}
 92→	if d.Name == "" {
 93→		return fmt.Errorf("connector %q missing required field: name", d.ID)
 94→	}
 95→	if d.Type == "" {
 96→		return fmt.Errorf("connector %q missing required field: type", d.ID)
 97→	}
 98→	if d.Auth.Method == "" {
 99→		return fmt.Errorf("connector %q missing required field: auth.method", d.ID)
100→	}
101→
102→	switch d.Auth.Method {
103→	case "oauth2":
104→		if d.Auth.AuthorizeURL == "" {
105→			return fmt.Errorf("connector %q (oauth2) missing auth.authorize_url", d.ID)
106→		}
107→		if d.Auth.TokenURL == "" {
108→			return fmt.Errorf("connector %q (oauth2) missing auth.token_url", d.ID)
109→		}
110→	case "api_key":
111→		if d.Auth.Header == "" && d.Auth.QueryParam == "" {
112→			return fmt.Errorf("connector %q (api_key) missing auth.header or auth.query_param", d.ID)
113→		}
114→	case "basic":
115→		// valid — credentials resolved at connect time
116→	case "webhook":
117→		// valid — URL resolved at connect time
118→	default:
119→		return fmt.Errorf("connector %q has unknown auth.method: %q", d.ID, d.Auth.Method)
120→	}
121→
122→	return nil
123→}
