  1→package connector
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"os"
  8→
  9→	"golang.org/x/oauth2"
 10→	"golang.org/x/oauth2/google"
 11→)
 12→
 13→func (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
 14→	var oauthCfg *oauth2.Config
 15→	var authOpts []oauth2.AuthCodeOption
 16→
 17→	if g.def.Credentials.Source == "google_json" {
 18→		// Google-specific: use google.ConfigFromJSON
 19→		credsData, err := g.loadGoogleCredentials()
 20→		if err != nil {
 21→			return nil, err
 22→		}
 23→		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
 24→		if err != nil {
 25→			return nil, fmt.Errorf("parsing Google credentials: %w", err)
 26→		}
 27→		oauthCfg = cfg
 28→	} else {
 29→		// Generic OAuth2: build config from YAML
 30→		clientID, clientSecret, err := g.resolveOAuthCredentials()
 31→		if err != nil {
 32→			return nil, err
 33→		}
 34→		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
 35→		if err != nil {
 36→			return nil, err
 37→		}
 38→		oauthCfg = cfg
 39→		authOpts = opts
 40→	}
 41→
 42→	// Add extra_params as auth options for google_json too
 43→	if g.def.Credentials.Source == "google_json" {
 44→		for k, v := range g.def.Auth.ExtraParams {
 45→			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
 46→		}
 47→	}
 48→
 49→	// Run shared OAuth flow
 50→	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
 51→	if err != nil {
 52→		return nil, err
 53→	}
 54→
 55→	// Save token
 56→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 57→	tokenPath := tokenDir + "/token.json"
 58→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 59→		return nil, fmt.Errorf("creating connector dir: %w", err)
 60→	}
 61→	if err := saveToken(tokenPath, token); err != nil {
 62→		return nil, fmt.Errorf("saving token: %w", err)
 63→	}
 64→
 65→	// Verify connection + get account identifier
 66→	account, err := g.runVerify(ctx, oauthCfg, token)
 67→	if err != nil {
 68→		// Non-fatal: connected but can't verify
 69→		account = "connected (unverified)"
 70→	}
 71→
 72→	return &Result{
 73→		Account: account,
 74→		Token:   token,
 75→	}, nil
 76→}
 77→
 78→func (g *GenericConnector) connectAPIKey(ctx context.Context) (*Result, error) {
 79→	key := os.Getenv(g.def.Auth.EnvVar)
 80→	if key == "" {
 81→		// Check if stdin is a TTY for prompt
 82→		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
 83→			fmt.Printf("Enter your %s API key: ", g.def.Name)
 84→			fmt.Scanln(&key)
 85→		}
 86→		if key == "" {
 87→			return nil, fmt.Errorf("%s API key not found. Set %s environment variable", g.def.Name, g.def.Auth.EnvVar)
 88→		}
 89→	}
 90→
 91→	// Save API key
 92→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 93→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 94→		return nil, fmt.Errorf("creating connector dir: %w", err)
 95→	}
 96→	credsPath := tokenDir + "/credentials.json"
 97→	credsData, _ := json.Marshal(map[string]string{"api_key": key})
 98→	if err := os.WriteFile(credsPath, credsData, 0600); err != nil {
 99→		return nil, fmt.Errorf("saving credentials: %w", err)
100→	}
101→
102→	// Verify
103→	account, err := g.runVerifyAPIKey(ctx, key)
104→	if err != nil {
105→		account = "connected (unverified)"
106→	}
107→
108→	return &Result{
109→		Account: account,
110→		Meta:    map[string]string{"api_key": key},
111→	}, nil
112→}
113→
114→func (g *GenericConnector) connectBasic(ctx context.Context) (*Result, error) {
115→	username := os.Getenv(g.def.Auth.UsernameVar)
116→	password := os.Getenv(g.def.Auth.PasswordVar)
117→	if username == "" || password == "" {
118→		return nil, fmt.Errorf("%s credentials not found. Set %s and %s environment variables",
119→			g.def.Name, g.def.Auth.UsernameVar, g.def.Auth.PasswordVar)
120→	}
121→
122→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
123→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
124→		return nil, fmt.Errorf("creating connector dir: %w", err)
125→	}
126→	credsData, _ := json.Marshal(map[string]string{"username": username, "password": password})
127→	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
128→		return nil, fmt.Errorf("saving credentials: %w", err)
129→	}
130→
131→	return &Result{Account: username}, nil
132→}
133→
134→func (g *GenericConnector) connectWebhook(ctx context.Context) (*Result, error) {
135→	webhookURL := os.Getenv(g.def.Auth.URLVar)
136→	if webhookURL == "" {
137→		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
138→			fmt.Printf("Enter your %s webhook URL: ", g.def.Name)
139→			fmt.Scanln(&webhookURL)
140→		}
141→		if webhookURL == "" {
142→			return nil, fmt.Errorf("%s webhook URL not found. Set %s environment variable",
143→				g.def.Name, g.def.Auth.URLVar)
144→		}
145→	}
146→
147→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
148→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
149→		return nil, fmt.Errorf("creating connector dir: %w", err)
150→	}
151→	credsData, _ := json.Marshal(map[string]string{"webhook_url": webhookURL})
152→	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
153→		return nil, fmt.Errorf("saving credentials: %w", err)
154→	}
155→
156→	return &Result{Account: webhookURL}, nil
157→}
158→
159→// buildOAuthConfig creates a generic oauth2.Config from the YAML definition.
160→func (g *GenericConnector) buildOAuthConfig(clientID, clientSecret string) (*oauth2.Config, []oauth2.AuthCodeOption, error) {
161→	cfg := &oauth2.Config{
162→		ClientID:     clientID,
163→		ClientSecret: clientSecret,
164→		Scopes:       g.def.Auth.Scopes,
165→		Endpoint: oauth2.Endpoint{
166→			AuthURL:  g.def.Auth.AuthorizeURL,
167→			TokenURL: g.def.Auth.TokenURL,
168→		},
169→	}
170→
171→	// Auth style
172→	switch g.def.Auth.AuthStyle {
173→	case "in_params":
174→		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInParams
175→	case "in_header":
176→		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInHeader
177→	}
178→
179→	// Extra params become AuthCodeOptions
180→	var opts []oauth2.AuthCodeOption
181→	for k, v := range g.def.Auth.ExtraParams {
182→		opts = append(opts, oauth2.SetAuthURLParam(k, v))
183→	}
184→
185→	return cfg, opts, nil
186→}
187→
188→// resolveOAuthCredentials reads client ID and secret from the configured source.
189→func (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
190→	cred := g.def.Credentials
191→
192→	switch cred.Source {
193→	case "env":
194→		id := os.Getenv(cred.ClientIDVar)
195→		secret := os.Getenv(cred.ClientSecretVar)
196→		if id == "" || secret == "" {
197→			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
198→				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
199→		}
200→		return id, secret, nil
201→
202→	case "prompt":
203→		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
204→			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
205→		}
206→		var id, secret string
207→		fmt.Printf("Enter %s client ID: ", g.def.Name)
208→		fmt.Scanln(&id)
209→		fmt.Printf("Enter %s client secret: ", g.def.Name)
210→		fmt.Scanln(&secret)
211→		if id == "" || secret == "" {
212→			return "", "", fmt.Errorf("client ID and secret are required")
213→		}
214→		return id, secret, nil
215→
216→	default:
217→		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
218→	}
219→}
220→
221→// loadGoogleCredentials loads credentials for google_json source (fallback chain).
222→func (g *GenericConnector) loadGoogleCredentials() ([]byte, error) {
223→	// 1. Explicit path from --credentials flag
224→	if g.credentials != "" {
225→		data, err := os.ReadFile(g.credentials)
226→		if err != nil {
227→			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
228→		}
229→		return data, nil
230→	}
231→
232→	// 2. Local file in project
233→	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", g.def.ID)
234→	if data, err := os.ReadFile(localPath); err == nil {
235→		return data, nil
236→	}
237→
238→	// 3. Bundled credentials
239→	if len(BundledCredentials) > 0 {
240→		return BundledCredentials, nil
241→	}
242→
243→	return nil, fmt.Errorf("no %s credentials found -- provide a credentials.json file", g.def.Name)
244→}
