package connector

import (
	"context"
	"encoding/json"
	"fmt"
	"os"

	"golang.org/x/oauth2"
)

// GenericConnector implements Connector backed by a YAMLConnector definition.
type GenericConnector struct {
	def         *YAMLConnector
	credentials string // optional override path (e.g. --credentials flag)
}

// saveToken writes an OAuth2 token to disk with restricted permissions.
func saveToken(path string, token *oauth2.Token) error {
	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_TRUNC, 0600)
	if err != nil {
		return err
	}
	defer f.Close()
	return json.NewEncoder(f).Encode(token)
}

func (g *GenericConnector) ID() string   { return g.def.ID }
func (g *GenericConnector) Name() string { return g.def.Name }
func (g *GenericConnector) Type() string { return g.def.Type }

func (g *GenericConnector) Connect(ctx context.Context) (*Result, error) {
	switch g.def.Auth.Method {
	case "oauth2":
		return g.connectOAuth2(ctx)
	case "api_key":
		return g.connectAPIKey(ctx)
	case "basic":
		return g.connectBasic(ctx)
	case "webhook":
		return g.connectWebhook(ctx)
	default:
		return nil, fmt.Errorf("unsupported auth method: %s", g.def.Auth.Method)
	}
}

