 63→
 64→// PullExecutionState fetches execution-state rows changed since lastSyncVersion.
 65→func (c *ConvexClient) PullExecutionState(token string, lastSyncVersion int64) (*PullResponse, error) {
 66→	body, err := json.Marshal(map[string]any{
 67→		"token":        token,
 68→		"sync_version": lastSyncVersion,
 69→	})
 70→	if err != nil {
 71→		return nil, fmt.Errorf("marshaling pull request: %w", err)
 72→	}
 73→
 74→	resp, err := c.httpClient.Post(
 75→		c.baseURL+"/api/pull-execution-state",
 76→		"application/json",
 77→		bytes.NewReader(body),
 78→	)
 79→	if err != nil {
 80→		return nil, fmt.Errorf("calling pull-execution-state: %w", err)
 81→	}
 82→	defer resp.Body.Close()
 83→
 84→	data, err := io.ReadAll(resp.Body)
 85→	if err != nil {
 86→		return nil, fmt.Errorf("reading response: %w", err)
 87→	}
 88→
 89→	if resp.StatusCode != 200 {
 90→		return nil, fmt.Errorf("pull-execution-state failed (status %d): %s", resp.StatusCode, string(data))
 91→	}
 92→
 93→	var result PullResponse
 94→	if err := json.Unmarshal(data, &result); err != nil {
 95→		return nil, fmt.Errorf("parsing pull response: %w", err)
 96→	}
 97→	return &result, nil
 98→}
