100→// PushLocalState pushes local-state changes to Convex.
101→func (c *ConvexClient) PushLocalState(token string, rows []SyncRow) (*PushResponse, error) {
102→	body, err := json.Marshal(map[string]any{
103→		"token": token,
104→		"rows":  rows,
105→	})
106→	if err != nil {
107→		return nil, fmt.Errorf("marshaling push request: %w", err)
108→	}
109→
110→	resp, err := c.httpClient.Post(
111→		c.baseURL+"/api/push-local-state",
112→		"application/json",
113→		bytes.NewReader(body),
114→	)
115→	if err != nil {
116→		return nil, fmt.Errorf("calling push-local-state: %w", err)
117→	}
118→	defer resp.Body.Close()
119→
120→	data, err := io.ReadAll(resp.Body)
121→	if err != nil {
122→		return nil, fmt.Errorf("reading response: %w", err)
123→	}
124→
125→	if resp.StatusCode != 200 {
126→		return nil, fmt.Errorf("push-local-state failed (status %d): %s", resp.StatusCode, string(data))
127→	}
128→
129→	var result PushResponse
130→	if err := json.Unmarshal(data, &result); err != nil {
131→		return nil, fmt.Errorf("parsing push response: %w", err)
132→	}
133→	return &result, nil
134→}
