 1→package account
 2→
 3→import (
 4→	"encoding/json"
 5→	"fmt"
 6→	"os"
 7→	"path/filepath"
 8→)
 9→
10→// AuthFile represents the local auth credentials stored at ~/.nurge/auth.json.
11→type AuthFile struct {
12→	Token             string `json:"token"`
13→	Email             string `json:"email"`
14→	Name              string `json:"name"`
15→	GoogleRefreshToken string `json:"google_refresh_token,omitempty"`
16→	CreatedAt         string `json:"created_at,omitempty"`
17→	ValidatedAt       string `json:"validated_at,omitempty"`
18→}
19→
20→func authDir() (string, error) {
21→	home, err := os.UserHomeDir()
22→	if err != nil {
23→		return "", fmt.Errorf("getting home directory: %w", err)
24→	}
25→	return filepath.Join(home, ".nurge"), nil
26→}
27→
28→func authFilePath() (string, error) {
29→	dir, err := authDir()
30→	if err != nil {
31→		return "", err
32→	}
33→	return filepath.Join(dir, "auth.json"), nil
34→}
35→
36→// LoadAuth reads the auth file from ~/.nurge/auth.json.
37→func LoadAuth() (*AuthFile, error) {
38→	path, err := authFilePath()
39→	if err != nil {
40→		return nil, err
41→	}
42→	data, err := os.ReadFile(path)
43→	if err != nil {
44→		return nil, fmt.Errorf("reading auth file: %w", err)
45→	}
46→	var af AuthFile
47→	if err := json.Unmarshal(data, &af); err != nil {
48→		return nil, fmt.Errorf("parsing auth file: %w", err)
49→	}
50→	return &af, nil
51→}
52→
53→// SaveAuth writes the auth file to ~/.nurge/auth.json.
54→// Creates ~/.nurge/ with 0700 if it doesn't exist.
55→// Writes auth.json with 0600 permissions.
56→func SaveAuth(af *AuthFile) error {
57→	dir, err := authDir()
58→	if err != nil {
59→		return err
60→	}
61→	if err := os.MkdirAll(dir, 0700); err != nil {
62→		return fmt.Errorf("creating auth directory: %w", err)
63→	}
64→
65→	data, err := json.MarshalIndent(af, "", "  ")
66→	if err != nil {
67→		return fmt.Errorf("marshaling auth file: %w", err)
68→	}
69→
70→	path := filepath.Join(dir, "auth.json")
71→	if err := os.WriteFile(path, data, 0600); err != nil {
72→		return fmt.Errorf("writing auth file: %w", err)
73→	}
74→	return nil
75→}
76→
77→// DeleteAuth removes ~/.nurge/auth.json.
78→func DeleteAuth() error {
79→	path, err := authFilePath()
80→	if err != nil {
81→		return err
82→	}
83→	if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
84→		return fmt.Errorf("deleting auth file: %w", err)
85→	}
86→	return nil
87→}
