 85→// ExchangeGoogleToken exchanges a Google ID token for a Nurge API token.
 86→func (c *ConvexClient) ExchangeGoogleToken(idToken string) (*exchangeResponse, error) {
 87→	body, err := json.Marshal(map[string]string{"id_token": idToken})
 88→	if err != nil {
 89→		return nil, fmt.Errorf("marshaling request: %w", err)
 90→	}
 91→	resp, err := c.httpClient.Post(
 92→		c.baseURL+"/api/google-auth",
 93→		"application/json",
 94→		bytes.NewReader(body),
 95→	)
 96→	if err != nil {
 97→		return nil, fmt.Errorf("calling google-auth: %w", err)
 98→	}
 99→	defer resp.Body.Close()
100→
101→	data, err := io.ReadAll(resp.Body)
102→	if err != nil {
103→		return nil, fmt.Errorf("reading response: %w", err)
104→	}
105→
106→	if resp.StatusCode != 200 {
107→		var errResp struct {
108→			Error string `json:"error"`
109→		}
110→		if err := json.Unmarshal(data, &errResp); err != nil || errResp.Error == "" {
111→			return nil, fmt.Errorf("google auth failed (HTTP %d): %s", resp.StatusCode, string(data))
112→		}
113→		return nil, fmt.Errorf("google auth failed: %s", errResp.Error)
114→	}
115→
116→	var result exchangeResponse
117→	if err := json.Unmarshal(data, &result); err != nil {
118→		return nil, fmt.Errorf("parsing response: %w", err)
119→	}
120→	return &result, nil
121→}
