package conn

import (
	"fmt"
	"os"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/util"
)

var connectCmd = &cobra.Command{
	Use:   "connect <service>",
	Short: "Connect a service (gmail, linkedin)",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id := args[0]
		switch id {
		case "gmail":
			return connectGmail()
		case "linkedin":
			return connectLinkedIn()
		default:
			fmt.Printf("Unknown service: %s\n", id)
			fmt.Println("Available: gmail, linkedin")
			return fmt.Errorf("unknown service: %s", id)
		}
	},
}

func connectGmail() error {
	af, err := account.LoadAuth()
	if err != nil || af.Token == "" {
		return fmt.Errorf("not logged in. Run: nurge account login")
	}

	client := account.NewConvexClient(cmdutil.GetConvexURL())

	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
	resp, err := client.ConnectGmail(af.Token)
	if err != nil {
		return fmt.Errorf("connect failed: %w", err)
	}

	if resp.AlreadyConnected {
		if resp.MaxReached {
			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Max 2 Gmail accounts connected (%s)\n", resp.Email)
		} else {
			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Gmail already connected (%s)\n", resp.Email)
		}
		if project.IsNurgeProject(".") {
			_ = project.SetConnector("gmail", "email", resp.Email)
		}
		return nil
	}

	fmt.Fprintf(os.Stderr, "  Opening browser to connect Gmail...\n")
	if err := util.OpenBrowser(resp.URL); err != nil {
		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
	}

	fmt.Fprintf(os.Stderr, "  Waiting for Gmail connection...")
	timeout := time.After(5 * time.Minute)
	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-timeout:
			fmt.Fprintf(os.Stderr, "\n")
			return fmt.Errorf("timed out waiting for Gmail connection")
		case <-ticker.C:
			status, err := client.ConnectionStatus(af.Token, "GOOGLE")
			if err != nil {
				continue
			}
			if status.Connected {
				fmt.Fprintf(os.Stderr, "\n  \033[32m✓\033[0m Gmail connected (%s)\n", status.Email)
				if project.IsNurgeProject(".") {
					_ = project.SetConnector("gmail", "email", status.Email)
				}
				return nil
			}
			fmt.Fprintf(os.Stderr, ".")
		}
	}
}

func connectLinkedIn() error {
	af, err := account.LoadAuth()
	if err != nil || af.Token == "" {
		return fmt.Errorf("not logged in. Run: nurge account login")
	}

	client := account.NewConvexClient(cmdutil.GetConvexURL())

	fmt.Fprintf(os.Stderr, "  Requesting LinkedIn connection...\n")
	resp, err := client.ConnectLinkedIn(af.Token)
	if err != nil {
		return fmt.Errorf("connect failed: %w", err)
	}

	if resp.AlreadyConnected {
		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m LinkedIn already connected (%s)\n", resp.Name)
		if project.IsNurgeProject(".") {
			_ = project.SetConnector("linkedin", "social", resp.Name)
		}
		return nil
	}

	fmt.Fprintf(os.Stderr, "  Opening browser to connect LinkedIn...\n")
	if err := util.OpenBrowser(resp.URL); err != nil {
		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
	}

	fmt.Fprintf(os.Stderr, "  Waiting for LinkedIn connection...")
	timeout := time.After(5 * time.Minute)
	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-timeout:
			fmt.Fprintf(os.Stderr, "\n")
			return fmt.Errorf("timed out waiting for LinkedIn connection")
		case <-ticker.C:
			status, err := client.ConnectionStatus(af.Token, "LINKEDIN")
			if err != nil {
				continue
			}
			if status.Connected {
				fmt.Fprintf(os.Stderr, "\n  \033[32m✓\033[0m LinkedIn connected (%s)\n", status.Name)
				if project.IsNurgeProject(".") {
					_ = project.SetConnector("linkedin", "social", status.Name)
				}
				return nil
			}
			fmt.Fprintf(os.Stderr, ".")
		}
	}
}

package conn

import (
	"fmt"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/project"
)

var disconnectCmd = &cobra.Command{
	Use:   "disconnect <connector>",
	Short: "Disconnect a service (gmail, hubspot)",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id := args[0]

		cfg, err := project.Load()
		if err != nil {
			return fmt.Errorf("loading config: %w", err)
		}

		cs, ok := cfg.Connectors[id]
		if !ok || !cs.Connected {
			return fmt.Errorf("%s is not connected", id)
		}

		// Remove token file
		tokenDir := fmt.Sprintf(".nurge/connectors/%s", id)
		if err := os.RemoveAll(tokenDir); err != nil {
			return fmt.Errorf("removing connector directory %s: %w", tokenDir, err)
		}

		// Remove from config
		if err := project.RemoveConnector(id); err != nil {
			return fmt.Errorf("updating config: %w", err)
		}

		fmt.Printf("\033[32m✓\033[0m %s disconnected\n", id)
		return nil
	},
}

package connector

import (
	"context"
	"encoding/json"
	"fmt"
	"os"

	"golang.org/x/oauth2"
)

// GenericConnector implements Connector backed by a YAMLConnector definition.
type GenericConnector struct {
	def         *YAMLConnector
	credentials string // optional override path (e.g. --credentials flag)
}

// saveToken writes an OAuth2 token to disk with restricted permissions.
func saveToken(path string, token *oauth2.Token) error {
	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_TRUNC, 0600)
	if err != nil {
		return err
	}
	defer f.Close()
	return json.NewEncoder(f).Encode(token)
}

func (g *GenericConnector) ID() string   { return g.def.ID }
func (g *GenericConnector) Name() string { return g.def.Name }
func (g *GenericConnector) Type() string { return g.def.Type }

func (g *GenericConnector) Connect(ctx context.Context) (*Result, error) {
	switch g.def.Auth.Method {
	case "oauth2":
		return g.connectOAuth2(ctx)
	case "api_key":
		return g.connectAPIKey(ctx)
	case "basic":
		return g.connectBasic(ctx)
	case "webhook":
		return g.connectWebhook(ctx)
	default:
		return nil, fmt.Errorf("unsupported auth method: %s", g.def.Auth.Method)
	}
}

