package connector

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"strings"

	"golang.org/x/oauth2"
)

// runVerify calls the verify endpoint using the oauth2 token source (handles refresh).
func (g *GenericConnector) runVerify(ctx context.Context, cfg *oauth2.Config, token *oauth2.Token) (string, error) {
	if g.def.Verify.URL == "" {
		return "connected", nil
	}

	// Refresh token first so URL substitution uses a valid access token
	ts := cfg.TokenSource(ctx, token)
	freshToken, err := ts.Token()
	if err != nil {
		fmt.Fprintf(os.Stderr, "  warning: token refresh failed: %v, falling back to original token\n", err)
		freshToken = token // fall back to original if refresh fails
	}
	if freshToken.AccessToken == "" {
		return "", fmt.Errorf("no valid access token: refresh failed (%v) and original token has empty access token", err)
	}
	client := oauth2.NewClient(ctx, ts)
	url := strings.ReplaceAll(g.def.Verify.URL, "{{access_token}}", freshToken.AccessToken)

	method := g.def.Verify.Method
	if method == "" {
		method = "GET"
	}

	req, err := http.NewRequestWithContext(ctx, method, url, nil)
	if err != nil {
		return "", err
	}
	for k, v := range g.def.Verify.Headers {
		v = strings.ReplaceAll(v, "{{access_token}}", freshToken.AccessToken)
		req.Header.Set(k, v)
	}

	resp, err := client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		return "", fmt.Errorf("verify returned %d", resp.StatusCode)
	}

	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
}

// runVerifyAPIKey calls verify with an API key in the configured header.
func (g *GenericConnector) runVerifyAPIKey(ctx context.Context, key string) (string, error) {
	if g.def.Verify.URL == "" {
		return "connected", nil
	}

	url := strings.ReplaceAll(g.def.Verify.URL, "{{api_key}}", key)
	method := g.def.Verify.Method
	if method == "" {
		method = "GET"
	}

	req, err := http.NewRequestWithContext(ctx, method, url, nil)
	if err != nil {
		return "", err
	}

	if g.def.Auth.Header != "" {
		req.Header.Set(g.def.Auth.Header, key)
	}

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		return "", fmt.Errorf("verify returned %d", resp.StatusCode)
	}

	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
}

// extractAccountField reads the JSON response and tries fields in preference order.
func extractAccountField(body io.Reader, fields []string) (string, error) {
	if len(fields) == 0 {
		return "connected", nil
	}

	var data map[string]interface{}
	if err := json.NewDecoder(body).Decode(&data); err != nil {
		return "", fmt.Errorf("parsing verify response: %w", err)
	}

	for _, field := range fields {
		if v, ok := data[field]; ok && v != nil {
			return fmt.Sprintf("%v", v), nil
		}
	}

	return "connected", nil
}

package connector

import (
	"context"
	"fmt"
	"time"

	"github.com/usenurge/nurgesh/internal/util"
	"golang.org/x/oauth2"
)

// OAuthFlow runs the shared OAuth2 local-server flow.
// It starts a local HTTP server, opens the browser to the auth URL,
// waits for the callback with the auth code, and exchanges it for tokens.
func OAuthFlow(ctx context.Context, cfg *oauth2.Config, authOpts ...oauth2.AuthCodeOption) (*oauth2.Token, error) {
	port, resultCh, errCh, cleanup, err := util.ListenAndWait(120 * time.Second)
	if err != nil {
		return nil, err
	}
	defer cleanup()

	cfg.RedirectURL = fmt.Sprintf("http://localhost:%d/callback", port)
	authURL := cfg.AuthCodeURL("nurge-state", authOpts...)

	if err := util.OpenBrowser(authURL); err != nil {
		return nil, fmt.Errorf("opening browser: %w\n  Please open this URL manually:\n  %s", err, authURL)
	}

	select {
	case result := <-resultCh:
		code := result.Values.Get("code")
		if code == "" {
			return nil, fmt.Errorf("no authorization code received")
		}
		token, err := cfg.Exchange(ctx, code)
		if err != nil {
			return nil, fmt.Errorf("exchanging code for token: %w", err)
		}
		return token, nil
	case err := <-errCh:
		return nil, err
	case <-ctx.Done():
		return nil, ctx.Err()
	}
}

package connector

import (
	"context"

	"golang.org/x/oauth2"
)

// Connector is the interface each service implements.
type Connector interface {
	ID() string
	Name() string
	Type() string
	Connect(ctx context.Context) (*Result, error)
}

// Result holds the output of a successful connection.
type Result struct {
	Account string
	Token   *oauth2.Token
	Meta    map[string]string
}

// ConnectorDef is a registry entry backed by a YAML definition.
type ConnectorDef struct {
	ID       string
	Name     string
	Type     string
	Tier     int
	Required bool
	Def      *YAMLConnector
}

// NewFromDef creates a GenericConnector from a ConnectorDef.
// credentials is an optional override path (e.g. --credentials flag), pass "" to skip.
func NewFromDef(def ConnectorDef, credentials string) Connector {
	return &GenericConnector{def: def.Def, credentials: credentials}
}

