package project

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

const configFile = ".nurge/config.json"
const configLockFile = ".nurge/config.lock"

// withConfigLock acquires an exclusive file lock on the config lockfile,
// runs fn, then releases the lock. This prevents TOCTOU race conditions
// when multiple processes do Load -> modify -> Write concurrently.
func withConfigLock(fn func() error) error {
	f, err := os.OpenFile(configLockFile, os.O_CREATE|os.O_RDWR, 0600)
	if err != nil {
		return fmt.Errorf("opening config lock: %w", err)
	}
	defer f.Close()

	if err := flockExclusive(int(f.Fd())); err != nil {
		return fmt.Errorf("acquiring config lock: %w", err)
	}
	defer flockUnlock(int(f.Fd()))

	return fn()
}

// ConnectorState holds the state of a single connected service.
type ConnectorState struct {
	Connected   bool   `json:"connected"`
	ConnectedAt string `json:"connected_at,omitempty"`
	Account     string `json:"account,omitempty"`
	Type        string `json:"type"` // "crm" or "email"
}

// Config is the top-level nurge configuration.
type Config struct {
	Version        int                        `json:"version"`
	CreatedAt      string                     `json:"created_at"`
	Connectors     map[string]ConnectorState  `json:"connectors"`
	SetupCompleted bool                       `json:"setup_completed"`
	Settings       map[string]string          `json:"settings,omitempty"`
}

// Path returns the path to config.json.
func Path() string {
	return configFile
}

// Default returns a new Config with default values.
func Default() *Config {
	return &Config{
		Version:        1,
		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
		Connectors:     make(map[string]ConnectorState),
		SetupCompleted: false,
	}
}

// Load reads config from disk.
func Load() (*Config, error) {
	data, err := os.ReadFile(configFile)
	if err != nil {
		return nil, fmt.Errorf("reading config: %w", err)
	}
	var cfg Config
	if err := json.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parsing config: %w", err)
	}
	if cfg.Connectors == nil {
		cfg.Connectors = make(map[string]ConnectorState)
	}
	return &cfg, nil
}

// Write saves config to disk.
func Write(cfg *Config) error {
	data, err := json.MarshalIndent(cfg, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling config: %w", err)
	}
	if err := os.WriteFile(configFile, data, 0600); err != nil {
		return fmt.Errorf("writing config: %w", err)
	}
	return nil
}

// SetConnector updates a connector in the config and saves.
func SetConnector(id, connType, account string) error {
	return withConfigLock(func() error {
		cfg, err := Load()
		if err != nil {
			return err
		}
		cfg.Connectors[id] = ConnectorState{
			Connected:   true,
			ConnectedAt: time.Now().UTC().Format(time.RFC3339),
			Account:     account,
			Type:        connType,
		}
		return Write(cfg)
	})
}

// RemoveConnector removes a connector from config and saves.
func RemoveConnector(id string) error {
	return withConfigLock(func() error {
		cfg, err := Load()
		if err != nil {
			return err
		}
		delete(cfg.Connectors, id)
		return Write(cfg)
	})
}

// Get returns the value for a settings key, or empty string if not set.
func Get(key string) (string, error) {
	cfg, err := Load()
	if err != nil {
		return "", err
	}
	if cfg.Settings == nil {
		return "", nil
	}
	return cfg.Settings[key], nil
}

// Set stores a key/value pair in settings and saves the config.
func Set(key, value string) error {
	return withConfigLock(func() error {
		cfg, err := Load()
		if err != nil {
			return err
		}
		if cfg.Settings == nil {
			cfg.Settings = make(map[string]string)
		}
		cfg.Settings[key] = value
		return Write(cfg)
	})
}

// SetSetupCompleted sets the top-level setup_completed flag and saves.
// When marking as complete, also removes the global setup skill -- it's no longer needed.
func SetSetupCompleted(completed bool) error {
	return withConfigLock(func() error {
		cfg, err := Load()
		if err != nil {
			return err
		}
		cfg.SetupCompleted = completed
		if err := Write(cfg); err != nil {
			return err
		}
		if completed {
			removeSetupSkill()
		}
		return nil
	})
}

// removeSetupSkill deletes the global setup skill directory.
// Graceful — ignores errors if already removed.
func removeSetupSkill() {
	home, err := os.UserHomeDir()
	if err != nil {
		return
	}
	os.RemoveAll(filepath.Join(home, ".claude", "skills", "nurge-setup"))
}

package util

import (
	"fmt"
	"net"
	"net/http"
	"net/url"
	"sync"
	"time"
)

// Result holds the query parameters from the callback.
type Result struct {
	Values url.Values
}

// ListenAndWait starts a local HTTP server on a random port, waits for a
// single request to /callback, and returns the query parameters.
// The caller must call the returned cleanup function when done.
func ListenAndWait(timeout time.Duration) (port int, resultCh <-chan Result, errCh <-chan error, cleanup func(), err error) {
	listener, err := net.Listen("tcp", "localhost:0")
	if err != nil {
		return 0, nil, nil, nil, fmt.Errorf("finding free port: %w", err)
	}
	port = listener.Addr().(*net.TCPAddr).Port

	rCh := make(chan Result, 1)
	eCh := make(chan error, 1)

	// once ensures only one of (timeout, callback success, callback error)
	// sends on the channels, preventing a race when both fire concurrently.
	var once sync.Once

	mux := http.NewServeMux()
	mux.HandleFunc("/callback", func(w http.ResponseWriter, r *http.Request) {
		errParam := r.URL.Query().Get("error")
		if errParam != "" {
			fmt.Fprintf(w, "<html><body><h2>Error</h2><p>%s</p><p>You can close this tab.</p></body></html>", errParam)
			once.Do(func() {
				eCh <- fmt.Errorf("callback error: %s", errParam)
			})
			return
		}
		fmt.Fprintf(w, "<html><body><h2>Success!</h2><p>You can close this tab and return to the terminal.</p></body></html>")
		once.Do(func() {
			rCh <- Result{Values: r.URL.Query()}
		})
	})

	server := &http.Server{Handler: mux}
	go server.Serve(listener)

	var cleanupOnce sync.Once
	cleanupFn := func() {
		cleanupOnce.Do(func() {
			server.Close()
		})
	}

	// Timeout goroutine
	go func() {
		<-time.After(timeout)
		once.Do(func() {
			eCh <- fmt.Errorf("timed out after %s", timeout)
		})
		cleanupFn()
	}()

	return port, rCh, eCh, cleanupFn, nil
}

package util

import (
	"fmt"
	"os/exec"
	"runtime"
)

// Open opens the given URL in the user's default browser.
func OpenBrowser(url string) error {
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "darwin":
		cmd = exec.Command("open", url)
	case "linux":
		cmd = exec.Command("xdg-open", url)
	case "windows":
		cmd = exec.Command("rundll32", "url.dll,FileProtocolHandler", url)
	default:
		return fmt.Errorf("unsupported platform %s", runtime.GOOS)
	}
	return cmd.Start()
}

