package connector

import (
	"testing"
)

func TestGenericConnector_IDNameType(t *testing.T) {
	def := &YAMLConnector{
		ID:   "test-crm",
		Name: "Test CRM",
		Type: "crm",
	}
	gc := &GenericConnector{def: def}

	if gc.ID() != "test-crm" {
		t.Errorf("ID() = %q, want test-crm", gc.ID())
	}
	if gc.Name() != "Test CRM" {
		t.Errorf("Name() = %q, want Test CRM", gc.Name())
	}
	if gc.Type() != "crm" {
		t.Errorf("Type() = %q, want crm", gc.Type())
	}
}

func TestBuildOAuthConfig(t *testing.T) {
	def := &YAMLConnector{
		ID: "hubspot",
		Auth: AuthConfig{
			Method:       "oauth2",
			AuthorizeURL: "https://app.hubspot.com/oauth/authorize",
			TokenURL:     "https://api.hubapi.com/oauth/v1/token",
			Scopes:       []string{"contacts.read", "deals.read"},
		},
	}

	gc := &GenericConnector{def: def}
	cfg, opts, err := gc.buildOAuthConfig("test-client-id", "test-secret")
	if err != nil {
		t.Fatalf("buildOAuthConfig: %v", err)
	}
	if cfg.ClientID != "test-client-id" {
		t.Errorf("ClientID = %q, want test-client-id", cfg.ClientID)
	}
	if cfg.Endpoint.AuthURL != "https://app.hubspot.com/oauth/authorize" {
		t.Errorf("AuthURL = %q", cfg.Endpoint.AuthURL)
	}
	if len(cfg.Scopes) != 2 {
		t.Errorf("Scopes len = %d, want 2", len(cfg.Scopes))
	}
	if len(opts) != 0 {
		t.Errorf("expected no extra opts for hubspot, got %d", len(opts))
	}
}

func TestBuildOAuthConfig_ExtraParams(t *testing.T) {
	def := &YAMLConnector{
		ID: "gmail",
		Auth: AuthConfig{
			Method:       "oauth2",
			AuthorizeURL: "https://accounts.google.com/o/oauth2/auth",
			TokenURL:     "https://oauth2.googleapis.com/token",
			Scopes:       []string{"gmail.readonly"},
			ExtraParams:  map[string]string{"access_type": "offline", "prompt": "select_account"},
		},
	}

	gc := &GenericConnector{def: def}
	_, opts, err := gc.buildOAuthConfig("id", "secret")
	if err != nil {
		t.Fatalf("buildOAuthConfig: %v", err)
	}
	if len(opts) != 2 {
		t.Errorf("expected 2 extra opts, got %d", len(opts))
	}
}

