 34→func connectGmail() error {
 35→	af, err := account.LoadAuth()
 36→	if err != nil || af.Token == "" {
 37→		return fmt.Errorf("not logged in. Run: nurge account login")
 38→	}
 39→
 40→	client := account.NewConvexClient(cmdutil.GetConvexURL())
 41→
 42→	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
 43→	resp, err := client.ConnectGmail(af.Token)
 44→	if err != nil {
 45→		return fmt.Errorf("connect failed: %w", err)
 46→	}
 47→
 48→	if resp.AlreadyConnected {
 49→		if resp.MaxReached {
 50→			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Max 2 Gmail accounts connected (%s)\n", resp.Email)
 51→		} else {
 52→			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Gmail already connected (%s)\n", resp.Email)
 53→		}
 54→		if project.IsNurgeProject(".") {
 55→			_ = project.SetConnector("gmail", "email", resp.Email)
 56→		}
 57→		return nil
 58→	}
 59→
 60→	fmt.Fprintf(os.Stderr, "  Opening browser to connect Gmail...\n")
 61→	if err := util.OpenBrowser(resp.URL); err != nil {
 62→		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
 63→	}
 64→
 65→	fmt.Fprintf(os.Stderr, "  Waiting for Gmail connection...")
 66→	timeout := time.After(5 * time.Minute)
 67→	ticker := time.NewTicker(2 * time.Second)
 68→	defer ticker.Stop()
 69→
 70→	for {
 71→		select {
 72→		case <-timeout:
 73→			fmt.Fprintf(os.Stderr, "\n")
 74→			return fmt.Errorf("timed out waiting for Gmail connection")
 75→		case <-ticker.C:
 76→			status, err := client.ConnectionStatus(af.Token, "GOOGLE")
 77→			if err != nil {
 78→				continue
 79→			}
 80→			if status.Connected {
 81→				fmt.Fprintf(os.Stderr, "\n  \033[32m✓\033[0m Gmail connected (%s)\n", status.Email)
 82→				if project.IsNurgeProject(".") {
 83→					_ = project.SetConnector("gmail", "email", status.Email)
 84→				}
 85→				return nil
 86→			}
 87→			fmt.Fprintf(os.Stderr, ".")
 88→		}
 89→	}
 90→}
