    ```go
    package connector

    import "fmt"

    type AuthError struct {
        ConnectorID string
        Reason      string
        Err         error
    }
    func (e *AuthError) Error() string   { return fmt.Sprintf("connector %s: %s", e.ConnectorID, e.Reason) }
    func (e *AuthError) Unwrap() error   { return e.Err }
    func (e *AuthError) Suggestion() string {
        return fmt.Sprintf("run `nurge connect %s` to reconnect", e.ConnectorID)
    }

    var (
        ErrAuthExpired   = fmt.Errorf("authentication expired")
        ErrTokenRevoked  = fmt.Errorf("token revoked by provider")
        ErrScopeMismatch = fmt.Errorf("insufficient scopes")
    )

    func IsAuthError(err error) bool {
        // Check for sentinel errors
        if errors.Is(err, ErrAuthExpired) || errors.Is(err, ErrTokenRevoked) {
            return true
        }
        // Check for AuthError wrapper
        var ae *AuthError
        return errors.As(err, &ae)
    }

    func NewAuthExpiredError(connectorID string, cause error) error {
        return &AuthError{ConnectorID: connectorID, Reason: "authentication expired", Err: fmt.Errorf("%w: %w", ErrAuthExpired, cause)}
    }
    func NewTokenRevokedError(connectorID string, cause error) error {
        return &AuthError{ConnectorID: connectorID, Reason: "token revoked by provider", Err: fmt.Errorf("%w: %w", ErrTokenRevoked, cause)}
    }
    func NewScopeMismatchError(connectorID string, needed, granted []string) error {
        return &AuthError{ConnectorID: connectorID, Reason: fmt.Sprintf("need scopes %v, have %v", needed, granted), Err: ErrScopeMismatch}
    }
    ```
  - Also add a helper: `ClassifyHTTPError(connectorID string, statusCode int, body string) error` that returns `NewAuthExpiredError` for 401, `NewTokenRevokedError` for 403 with "revoked" in body, and a plain `fmt.Errorf` otherwise
