var verifyCmd = &cobra.Command{
	Use:   "verify [id]",
	Short: "Verify connector health (all connectors if no id given)",
	Args:  cobra.MaximumNArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		cfg, err := project.Load()
		if err != nil {
			return fmt.Errorf("loading config: %w", err)
		}

		var targets []string
		if len(args) > 0 {
			targets = []string{args[0]}
		} else {
			for id, cs := range cfg.Connectors {
				if cs.Connected {
					targets = append(targets, id)
				}
			}
			sort.Strings(targets)
		}

		if len(targets) == 0 {
			fmt.Println("  No connectors configured")
			return nil
		}

		allOK := true
		for _, id := range targets {
			cs := cfg.Connectors[id]
			connDir := fmt.Sprintf(".nurge/connectors/%s", id)
			result := connector.CheckHealth(id, connDir, cs.Connected)
			switch result.Status {
			case connector.HealthOK:
				fmt.Printf("  \033[32m\u2713\033[0m %-15s healthy\n", id)
			default:
				allOK = false
				fmt.Printf("  \033[31m\u2717\033[0m %-15s %s\n", id, result.Message)
			}
		}
		if !allOK {
			return fmt.Errorf("some connectors have issues, run `nurge connect <id>` to fix")
		}
		return nil
	},
}
