func SaveGrantedScopes(connectorDir string, scopes []string) error {
	data, err := json.Marshal(scopes)
	if err != nil {
		return err
	}
	return os.WriteFile(filepath.Join(connectorDir, "scopes.json"), data, 0600)
}

func LoadGrantedScopes(connectorDir string) ([]string, error) {
	data, err := os.ReadFile(filepath.Join(connectorDir, "scopes.json"))
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}
	var scopes []string
	return scopes, json.Unmarshal(data, &scopes)
}

func CheckScopesSufficient(granted, required []string) bool {
	set := make(map[string]bool, len(granted))
	for _, s := range granted {
		set[s] = true
	}
	for _, s := range required {
		if !set[s] {
			return false
		}
	}
	return true
}
