func OAuthFlow(ctx context.Context, cfg *oauth2.Config, authOpts ...oauth2.AuthCodeOption) (*oauth2.Token, error) {
	port, resultCh, errCh, cleanup, err := util.ListenAndWait(120 * time.Second)
	if err != nil {
		return nil, err
	}
	defer cleanup()

	state, err := GenerateState()
	if err != nil {
		return nil, err
	}

	cfg.RedirectURL = fmt.Sprintf("http://localhost:%d/callback", port)
	authURL := cfg.AuthCodeURL(state, authOpts...)

	if err := util.OpenBrowser(authURL); err != nil {
		fmt.Fprintf(os.Stderr, "  Could not open browser automatically.\n  Please open this URL manually:\n  %s\n", authURL)
	}

	select {
	case result := <-resultCh:
		if err := ValidateState(state, result.Values.Get("state")); err != nil {
			return nil, err
		}
		code := result.Values.Get("code")
		if code == "" {
			return nil, fmt.Errorf("no authorization code received")
		}
		token, err := cfg.Exchange(ctx, code)
		if err != nil {
			return nil, fmt.Errorf("exchanging code for token: %w", err)
		}
		return token, nil
	case err := <-errCh:
		return nil, err
	case <-ctx.Done():
		return nil, ctx.Err()
	}
}
