```go
// internal/connector/errors.go
package connector

import (
	"errors"
	"fmt"
	"strings"
)

// AuthError wraps a connector authentication failure with actionable context.
type AuthError struct {
	ConnectorID string
	Reason      string
	Err         error
}

func (e *AuthError) Error() string { return fmt.Sprintf("connector %s: %s", e.ConnectorID, e.Reason) }
func (e *AuthError) Unwrap() error { return e.Err }
func (e *AuthError) Suggestion() string {
	return fmt.Sprintf("run `nurge connect %s` to reconnect", e.ConnectorID)
}

var (
	ErrAuthExpired   = fmt.Errorf("authentication expired")
	ErrTokenRevoked  = fmt.Errorf("token revoked by provider")
	ErrScopeMismatch = fmt.Errorf("insufficient scopes")
)

func IsAuthError(err error) bool {
	var ae *AuthError
	return errors.As(err, &ae)
}

func NewAuthExpiredError(connectorID string, cause error) error {
	return &AuthError{
		ConnectorID: connectorID,
		Reason:      "authentication expired",
		Err:         fmt.Errorf("%w: %w", ErrAuthExpired, cause),
	}
}

func NewTokenRevokedError(connectorID string, cause error) error {
	return &AuthError{
		ConnectorID: connectorID,
		Reason:      "token revoked by provider",
		Err:         fmt.Errorf("%w: %w", ErrTokenRevoked, cause),
	}
}

func NewScopeMismatchError(connectorID string, needed, granted []string) error {
	return &AuthError{
		ConnectorID: connectorID,
		Reason:      fmt.Sprintf("need scopes %v, have %v", needed, granted),
		Err:         ErrScopeMismatch,
	}
}

func ClassifyHTTPError(connectorID string, statusCode int, body string) error {
	switch {
	case statusCode == 401:
		return NewAuthExpiredError(connectorID, fmt.Errorf("HTTP %d", statusCode))
	case statusCode == 403:
		if strings.Contains(strings.ToLower(body), "revoked") {
			return NewTokenRevokedError(connectorID, fmt.Errorf("HTTP %d: %s", statusCode, body))
		}
		return NewAuthExpiredError(connectorID, fmt.Errorf("HTTP %d: %s", statusCode, body))
	default:
		return fmt.Errorf("HTTP %d: %s", statusCode, body)
	}
}
```

