```go
// internal/connector/health.go
package connector

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
)

type HealthStatus int

const (
	HealthOK HealthStatus = iota
	HealthTokenMissing
	HealthTokenCorrupt
	HealthOrphanedToken
)

func (h HealthStatus) String() string {
	switch h {
	case HealthOK:
		return "ok"
	case HealthTokenMissing:
		return "token_missing"
	case HealthTokenCorrupt:
		return "token_corrupt"
	case HealthOrphanedToken:
		return "orphaned_token"
	default:
		return "unknown"
	}
}

type HealthResult struct {
	ConnectorID string
	Status      HealthStatus
	Message     string
}

func CheckHealth(connectorID, connectorDir string, configConnected bool) HealthResult {
	tokenPath := filepath.Join(connectorDir, "token.json")
	credsPath := filepath.Join(connectorDir, "credentials.json")

	hasToken := fileExists(tokenPath)
	hasCreds := fileExists(credsPath)
	hasAnyAuth := hasToken || hasCreds

	if configConnected {
		if !hasAnyAuth {
			return HealthResult{
				ConnectorID: connectorID,
				Status:      HealthTokenMissing,
				Message:     fmt.Sprintf("config says connected but no token/credentials found in %s", connectorDir),
			}
		}
		// Validate token JSON
		if hasToken {
			if err := validateJSON(tokenPath); err != nil {
				return HealthResult{
					ConnectorID: connectorID,
					Status:      HealthTokenCorrupt,
					Message:     fmt.Sprintf("token.json is corrupt: %v", err),
				}
			}
		}
		if hasCreds && !hasToken {
			if err := validateJSON(credsPath); err != nil {
				return HealthResult{
					ConnectorID: connectorID,
					Status:      HealthTokenCorrupt,
					Message:     fmt.Sprintf("credentials.json is corrupt: %v", err),
				}
			}
		}
		return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy"}
	}

	// Not connected in config
	if hasAnyAuth {
		return HealthResult{
			ConnectorID: connectorID,
			Status:      HealthOrphanedToken,
			Message:     fmt.Sprintf("config says disconnected but auth files exist in %s", connectorDir),
		}
	}
	return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "clean"}
}

func fileExists(path string) bool {
	_, err := os.Stat(path)
	return err == nil
}

func validateJSON(path string) error {
	data, err := os.ReadFile(path)
	if err != nil {
		return err
	}
	var v interface{}
	return json.Unmarshal(data, &v)
}
```

