 10→	"strings"
 11→
 12→	"golang.org/x/oauth2"
 13→)
 14→
 15→// runVerify calls the verify endpoint using the oauth2 token source (handles refresh).
 16→func (g *GenericConnector) runVerify(ctx context.Context, cfg *oauth2.Config, token *oauth2.Token) (string, error) {
 17→	if g.def.Verify.URL == "" {
 18→		return "connected", nil
 19→	}
 20→
 21→	// Refresh token first so URL substitution uses a valid access token
 22→	ts := cfg.TokenSource(ctx, token)
 23→	freshToken, err := ts.Token()
 24→	if err != nil {
 25→		fmt.Fprintf(os.Stderr, "  warning: token refresh failed: %v, falling back to original token\n", err)
 26→		freshToken = token // fall back to original if refresh fails
 27→	}
 28→	if freshToken.AccessToken == "" {
 29→		return "", fmt.Errorf("no valid access token: refresh failed (%v) and original token has empty access token", err)
 30→	}
 31→	client := oauth2.NewClient(ctx, ts)
 32→	url := strings.ReplaceAll(g.def.Verify.URL, "{{access_token}}", freshToken.AccessToken)
 33→
 34→	method := g.def.Verify.Method
 35→	if method == "" {
 36→		method = "GET"
 37→	}
 38→
 39→	req, err := http.NewRequestWithContext(ctx, method, url, nil)
 40→	if err != nil {
 41→		return "", err
 42→	}
 43→	for k, v := range g.def.Verify.Headers {
 44→		v = strings.ReplaceAll(v, "{{access_token}}", freshToken.AccessToken)
 45→		req.Header.Set(k, v)
 46→	}
 47→
 48→	resp, err := client.Do(req)
 49→	if err != nil {
 50→		return "", err
 51→	}
 52→	defer resp.Body.Close()
 53→
 54→	if resp.StatusCode != 200 {
 55→		return "", fmt.Errorf("verify returned %d", resp.StatusCode)
 56→	}
 57→
 58→	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
 59→}
 60→
 61→// runVerifyAPIKey calls verify with an API key in the configured header.
 62→func (g *GenericConnector) runVerifyAPIKey(ctx context.Context, key string) (string, error) {
 63→	if g.def.Verify.URL == "" {
 64→		return "connected", nil
 65→	}
 66→
 67→	url := strings.ReplaceAll(g.def.Verify.URL, "{{api_key}}", key)
 68→	method := g.def.Verify.Method
 69→	if method == "" {
 70→		method = "GET"
 71→	}
 72→
 73→	req, err := http.NewRequestWithContext(ctx, method, url, nil)
 74→	if err != nil {
 75→		return "", err
 76→	}
 77→
 78→	if g.def.Auth.Header != "" {
 79→		req.Header.Set(g.def.Auth.Header, key)
 80→	}
 81→
 82→	resp, err := http.DefaultClient.Do(req)
 83→	if err != nil {
 84→		return "", err
 85→	}
 86→	defer resp.Body.Close()
 87→
 88→	if resp.StatusCode != 200 {
 89→		return "", fmt.Errorf("verify returned %d", resp.StatusCode)
 90→	}
 91→
 92→	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
 93→}
 94→
 95→// extractAccountField reads the JSON response and tries fields in preference order.
 96→func extractAccountField(body io.Reader, fields []string) (string, error) {
 97→	if len(fields) == 0 {
 98→		return "connected", nil
 99→	}
100→
101→	var data map[string]interface{}
102→	if err := json.NewDecoder(body).Decode(&data); err != nil {
103→		return "", fmt.Errorf("parsing verify response: %w", err)
104→	}
105→
106→	for _, field := range fields {
107→		if v, ok := data[field]; ok && v != nil {
108→			return fmt.Sprintf("%v", v), nil
109→		}
110→	}
111→
112→	return "connected", nil
113→}
