	tests := []struct {
		name     string
		granted  []string
		required []string
		want     bool
	}{
		{"all present", []string{"a", "b", "c"}, []string{"a", "b"}, true},
		{"exact match", []string{"a", "b"}, []string{"a", "b"}, true},
		{"missing one", []string{"a"}, []string{"a", "b"}, false},
		{"empty granted", []string{}, []string{"a"}, false},
		{"empty required", []string{"a"}, []string{}, true},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := CheckScopesSufficient(tt.granted, tt.required); got != tt.want {
				t.Errorf("got %v, want %v", got, tt.want)
			}
		})
	}
}
```

### Step 2: Implement scope tracking functions

Add these functions to `/Users/rejoesudarsan/Projects/nurgesh/internal/connector/health.go` (the file already exists with `CheckHealth`, `fileExists`, `validateJSON`):

```go
func SaveGrantedScopes(connectorDir string, scopes []string) error {
	data, err := json.Marshal(scopes)
	if err != nil {
		return err
	}
	return os.WriteFile(filepath.Join(connectorDir, "scopes.json"), data, 0600)
}

func LoadGrantedScopes(connectorDir string) ([]string, error) {
	data, err := os.ReadFile(filepath.Join(connectorDir, "scopes.json"))
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}
	var scopes []string
	return scopes, json.Unmarshal(data, &scopes)
}

func CheckScopesSufficient(granted, required []string) bool {
	set := make(map[string]bool, len(granted))
	for _, s := range granted {
		set[s] = true
	}
	for _, s := range required {
		if !set[s] {
			return false
		}
	}
	return true
}
```

Note: `json`, `os`, and `filepath` are already imported in health.go.

### Step 3: Save scopes on OAuth2 connect

Read `/Users/rejoesudarsan/Projects/nurgesh/internal/connector/generic_auth.go`. In the `connectOAuth2` method, after the `saveToken` call (around line 61-63), add:

```go
if len(g.def.Auth.Scopes) > 0 {
	_ = SaveGrantedScopes(tokenDir, g.def.Auth.Scopes)
}
```

This goes right after:
```go
if err := saveToken(tokenPath, token); err != nil {
	return nil, fmt.Errorf("saving token: %w", err)
}
```

And before:
```go
// Verify connection + get account identifier
account, err := g.runVerify(ctx, oauthCfg, token)
```

## Context

This fixes edge case #10 (scope changes between versions). When a user upgrades Nurge and the new version requires additional OAuth scopes, the existing token may not have them. By storing the granted scopes at connect time, we can detect this mismatch later (in the verify command or before operations that need specific scopes).

`SaveGrantedScopes` writes a `scopes.json` file alongside `token.json` in `.nurge/connectors/{id}/`. `LoadGrantedScopes` reads it back (returns nil, nil if missing -- graceful for old tokens). `CheckScopesSufficient` does set comparison.

The `g.def.Auth.Scopes` field on `YAMLConnector.AuthConfig` contains the scopes requested in the connector YAML definition.

