 10→// HealthStatus represents the outcome of a connector health check.
 11→type HealthStatus int
 12→
 13→const (
 14→	HealthOK           HealthStatus = iota
 15→	HealthTokenMissing              // config says connected but no auth files on disk
 16→	HealthTokenCorrupt              // auth file exists but contains invalid JSON
 17→	HealthOrphanedToken             // config says disconnected but auth files remain
 18→)
 19→
 20→func (h HealthStatus) String() string {
 21→	switch h {
 22→	case HealthOK:
 23→		return "ok"
 24→	case HealthTokenMissing:
 25→		return "token_missing"
 26→	case HealthTokenCorrupt:
 27→		return "token_corrupt"
 28→	case HealthOrphanedToken:
 29→		return "orphaned_token"
 30→	default:
 31→		return "unknown"
 32→	}
 33→}
 34→
 35→// HealthResult holds the outcome of CheckHealth for a single connector.
 36→type HealthResult struct {
 37→	ConnectorID string
 38→	Status      HealthStatus
 39→	Message     string
 40→}
 41→
 42→// CheckHealth verifies consistency between a connector's config state
 43→// (connected or not) and its on-disk auth files (token.json / credentials.json).
 44→func CheckHealth(connectorID, connectorDir string, configConnected bool) HealthResult {
 45→	tokenPath := filepath.Join(connectorDir, "token.json")
 46→	credsPath := filepath.Join(connectorDir, "credentials.json")
 47→
 48→	hasToken := fileExists(tokenPath)
 49→	hasCreds := fileExists(credsPath)
 50→	hasAnyAuth := hasToken || hasCreds
 51→
 52→	if configConnected {
 53→		if !hasAnyAuth {
 54→			return HealthResult{
 55→				ConnectorID: connectorID,
 56→				Status:      HealthTokenMissing,
 57→				Message:     fmt.Sprintf("config says connected but no token/credentials found in %s", connectorDir),
 58→			}
 59→		}
 60→		if hasToken {
 61→			if err := validateJSON(tokenPath); err != nil {
 62→				return HealthResult{
 63→					ConnectorID: connectorID,
 64→					Status:      HealthTokenCorrupt,
 65→					Message:     fmt.Sprintf("token.json is corrupt: %v", err),
 66→				}
 67→			}
 68→		}
 69→		if hasCreds && !hasToken {
 70→			if err := validateJSON(credsPath); err != nil {
 71→				return HealthResult{
 72→					ConnectorID: connectorID,
 73→					Status:      HealthTokenCorrupt,
 74→					Message:     fmt.Sprintf("credentials.json is corrupt: %v", err),
 75→				}
 76→			}
 77→		}
 78→		return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy"}
 79→	}
 80→
 81→	// Not connected according to config.
 82→	if hasAnyAuth {
 83→		return HealthResult{
 84→			ConnectorID: connectorID,
 85→			Status:      HealthOrphanedToken,
 86→			Message:     fmt.Sprintf("config says disconnected but auth files exist in %s", connectorDir),
 87→		}
 88→	}
 89→	return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "clean"}
 90→}
