 92→func fileExists(path string) bool {
 93→	_, err := os.Stat(path)
 94→	return err == nil
 95→}
 96→
 97→func validateJSON(path string) error {
 98→	data, err := os.ReadFile(path)
 99→	if err != nil {
100→		return err
101→	}
102→	var v interface{}
103→	return json.Unmarshal(data, &v)
104→}
