 13→func (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
 14→	var oauthCfg *oauth2.Config
 15→	var authOpts []oauth2.AuthCodeOption
 16→
 17→	if g.def.Credentials.Source == "google_json" {
 18→		// Google-specific: use google.ConfigFromJSON
 19→		credsData, err := g.loadGoogleCredentials()
 20→		if err != nil {
 21→			return nil, err
 22→		}
 23→		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
 24→		if err != nil {
 25→			return nil, fmt.Errorf("parsing Google credentials: %w", err)
 26→		}
 27→		oauthCfg = cfg
 28→	} else {
 29→		// Generic OAuth2: build config from YAML
 30→		clientID, clientSecret, err := g.resolveOAuthCredentials()
 31→		if err != nil {
 32→			return nil, err
 33→		}
 34→		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
 35→		if err != nil {
 36→			return nil, err
 37→		}
 38→		oauthCfg = cfg
 39→		authOpts = opts
 40→	}
 41→
 42→	// Add extra_params as auth options for google_json too
 43→	if g.def.Credentials.Source == "google_json" {
 44→		for k, v := range g.def.Auth.ExtraParams {
 45→			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
 46→		}
 47→	}
 48→
 49→	// Run shared OAuth flow
 50→	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
 51→	if err != nil {
 52→		return nil, err
 53→	}
 54→
 55→	// Save token
 56→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 57→	tokenPath := tokenDir + "/token.json"
 58→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 59→		return nil, fmt.Errorf("creating connector dir: %w", err)
 60→	}
 61→	if err := saveToken(tokenPath, token); err != nil {
 62→		return nil, fmt.Errorf("saving token: %w", err)
 63→	}
 64→
 65→	// Verify connection + get account identifier
 66→	account, err := g.runVerify(ctx, oauthCfg, token)
 67→	if err != nil {
 68→		// Non-fatal: connected but can't verify
 69→		account = "connected (unverified)"
 70→	}
 71→
 72→	return &Result{
 73→		Account: account,
 74→		Token:   token,
 75→	}, nil
 76→}
