+package connector
+
+import (
+	"encoding/json"
+	"fmt"
+	"os"
+	"path/filepath"
+)
+
+// HealthStatus represents the outcome of a connector health check.
+type HealthStatus int
+
+const (
+	HealthOK           HealthStatus = iota
+	HealthTokenMissing              // config says connected but no auth files on disk
+	HealthTokenCorrupt              // auth file exists but contains invalid JSON
+	HealthOrphanedToken             // config says disconnected but auth files remain
+)
+
+func (h HealthStatus) String() string {
+	switch h {
+	case HealthOK:
+		return "ok"
+	case HealthTokenMissing:
+		return "token_missing"
+	case HealthTokenCorrupt:
+		return "token_corrupt"
+	case HealthOrphanedToken:
+		return "orphaned_token"
+	default:
+		return "unknown"
+	}
+}
+
+// HealthResult holds the outcome of CheckHealth for a single connector.
+type HealthResult struct {
+	ConnectorID string
+	Status      HealthStatus
+	Message     string
+}
+
+// CheckHealth verifies consistency between a connector's config state
+// (connected or not) and its on-disk auth files (token.json / credentials.json).
+func CheckHealth(connectorID, connectorDir string, configConnected bool) HealthResult {
+	tokenPath := filepath.Join(connectorDir, "token.json")
+	credsPath := filepath.Join(connectorDir, "credentials.json")
+
+	hasToken := fileExists(tokenPath)
+	hasCreds := fileExists(credsPath)
+	hasAnyAuth := hasToken || hasCreds
+
+	if configConnected {
+		if !hasAnyAuth {
+			return HealthResult{
+				ConnectorID: connectorID,
+				Status:      HealthTokenMissing,
+				Message:     fmt.Sprintf("config says connected but no token/credentials found in %s", connectorDir),
+			}
+		}
+		if hasToken {
+			if err := validateJSON(tokenPath); err != nil {
+				return HealthResult{
+					ConnectorID: connectorID,
+					Status:      HealthTokenCorrupt,
+					Message:     fmt.Sprintf("token.json is corrupt: %v", err),
+				}
+			}
+		}
+		if hasCreds && !hasToken {
+			if err := validateJSON(credsPath); err != nil {
+				return HealthResult{
+					ConnectorID: connectorID,
+					Status:      HealthTokenCorrupt,
+					Message:     fmt.Sprintf("credentials.json is corrupt: %v", err),
+				}
+			}
+		}
+		return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy"}
+	}
+
+	// Not connected according to config.
+	if hasAnyAuth {
+		return HealthResult{
+			ConnectorID: connectorID,
+			Status:      HealthOrphanedToken,
+			Message:     fmt.Sprintf("config says disconnected but auth files exist in %s", connectorDir),
+		}
+	}
+	return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "clean"}
+}
+
+// SaveGrantedScopes writes the granted OAuth scopes to scopes.json in the connector directory.
+func SaveGrantedScopes(connectorDir string, scopes []string) error {
+	data, err := json.Marshal(scopes)
+	if err != nil {
+		return err
+	}
+	return os.WriteFile(filepath.Join(connectorDir, "scopes.json"), data, 0600)
+}
+
+// LoadGrantedScopes reads the granted OAuth scopes from scopes.json.
+// Returns nil, nil if the file does not exist (graceful for old tokens).
+func LoadGrantedScopes(connectorDir string) ([]string, error) {
+	data, err := os.ReadFile(filepath.Join(connectorDir, "scopes.json"))
+	if err != nil {
+		if os.IsNotExist(err) {
+			return nil, nil
+		}
+		return nil, err
+	}
+	var scopes []string
+	return scopes, json.Unmarshal(data, &scopes)
+}
+
+// CheckScopesSufficient returns true if all required scopes are present in granted.
+func CheckScopesSufficient(granted, required []string) bool {
+	set := make(map[string]bool, len(granted))
+	for _, s := range granted {
+		set[s] = true
+	}
+	for _, s := range required {
+		if !set[s] {
+			return false
+		}
+	}
+	return true
+}
+
+func fileExists(path string) bool {
+	_, err := os.Stat(path)
+	return err == nil
+}
+
+func validateJSON(path string) error {
+	data, err := os.ReadFile(path)
+	if err != nil {
+		return err
+	}
+	var v interface{}
+	return json.Unmarshal(data, &v)
+}
