113→	timeout := time.After(5 * time.Minute)
114→	ticker := time.NewTicker(2 * time.Second)
115→	defer ticker.Stop()
116→
117→	for {
118→		select {
119→		case <-timeout:
120→			fmt.Fprintf(os.Stderr, "\n")
121→			return fmt.Errorf("timed out after 5 minutes waiting for Gmail connection.\n  Run `nurge connect gmail` to try again")
122→		case <-ticker.C:
123→			status, err := client.ConnectionStatus(af.Token, "GOOGLE")
124→			if err != nil {
