10→	"time"
11→
12→	"github.com/usenurge/nurgesh/internal/util"
13→	"golang.org/x/oauth2"
14→)
15→
16→// GenerateState returns a 32-character hex string suitable for OAuth2 CSRF state.
17→func GenerateState() (string, error) {
18→	b := make([]byte, 16)
19→	if _, err := crypto_rand.Read(b); err != nil {
20→		return "", fmt.Errorf("generating state: %w", err)
21→	}
22→	return hex.EncodeToString(b), nil
23→}
24→
25→// ValidateState checks that the returned OAuth state matches the expected value
26→// using constant-time comparison to prevent timing attacks.
27→func ValidateState(expected, got string) error {
28→	if !hmac.Equal([]byte(expected), []byte(got)) {
29→		return fmt.Errorf("OAuth state mismatch (possible CSRF)")
30→	}
31→	return nil
32→}
33→
34→// OAuthFlow runs the shared OAuth2 local-server flow.
35→// It starts a local HTTP server, opens the browser to the auth URL,
36→// waits for the callback with the auth code, and exchanges it for tokens.
37→func OAuthFlow(ctx context.Context, cfg *oauth2.Config, authOpts ...oauth2.AuthCodeOption) (*oauth2.Token, error) {
38→	port, resultCh, errCh, cleanup, err := util.ListenAndWait(120 * time.Second)
39→	if err != nil {
40→		return nil, err
41→	}
42→	defer cleanup()
43→
44→	state, err := GenerateState()
45→	if err != nil {
46→		return nil, err
47→	}
48→
49→	cfg.RedirectURL = fmt.Sprintf("http://localhost:%d/callback", port)
50→	authURL := cfg.AuthCodeURL(state, authOpts...)
51→
52→	if err := util.OpenBrowser(authURL); err != nil {
53→		fmt.Fprintf(os.Stderr, "  Could not open browser automatically.\n  Please open this URL manually:\n  %s\n", authURL)
54→	}
55→
56→	select {
57→	case result := <-resultCh:
58→		if err := ValidateState(state, result.Values.Get("state")); err != nil {
59→			return nil, err
60→		}
61→		code := result.Values.Get("code")
62→		if code == "" {
63→			return nil, fmt.Errorf("no authorization code received")
64→		}
65→		token, err := cfg.Exchange(ctx, code)
66→		if err != nil {
67→			return nil, fmt.Errorf("exchanging code for token: %w", err)
68→		}
69→		return token, nil
70→	case err := <-errCh:
71→		return nil, err
72→	case <-ctx.Done():
73→		return nil, ctx.Err()
74→	}
75→}
