164→// buildOAuthConfig creates a generic oauth2.Config from the YAML definition.
165→func (g *GenericConnector) buildOAuthConfig(clientID, clientSecret string) (*oauth2.Config, []oauth2.AuthCodeOption, error) {
166→	cfg := &oauth2.Config{
167→		ClientID:     clientID,
168→		ClientSecret: clientSecret,
169→		Scopes:       g.def.Auth.Scopes,
170→		Endpoint: oauth2.Endpoint{
171→			AuthURL:  g.def.Auth.AuthorizeURL,
172→			TokenURL: g.def.Auth.TokenURL,
173→		},
174→	}
175→
176→	// Auth style
177→	switch g.def.Auth.AuthStyle {
178→	case "in_params":
179→		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInParams
180→	case "in_header":
181→		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInHeader
182→	}
183→
184→	// Extra params become AuthCodeOptions
185→	var opts []oauth2.AuthCodeOption
186→	for k, v := range g.def.Auth.ExtraParams {
187→		opts = append(opts, oauth2.SetAuthURLParam(k, v))
188→	}
189→
190→	return cfg, opts, nil
191→}
192→
193→// resolveOAuthCredentials reads client ID and secret from the configured source.
194→func (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
195→	cred := g.def.Credentials
196→
197→	switch cred.Source {
198→	case "env":
199→		id := os.Getenv(cred.ClientIDVar)
200→		secret := os.Getenv(cred.ClientSecretVar)
201→		if id == "" || secret == "" {
202→			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
203→				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
204→		}
205→		return id, secret, nil
206→
207→	case "prompt":
208→		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
209→			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
210→		}
211→		var id, secret string
212→		fmt.Printf("Enter %s client ID: ", g.def.Name)
213→		fmt.Scanln(&id)
214→		fmt.Printf("Enter %s client secret: ", g.def.Name)
215→		fmt.Scanln(&secret)
216→		if id == "" || secret == "" {
217→			return "", "", fmt.Errorf("client ID and secret are required")
218→		}
219→		return id, secret, nil
220→
221→	default:
222→		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
223→	}
224→}
225→
226→// loadGoogleCredentials loads credentials for google_json source (fallback chain).
227→func (g *GenericConnector) loadGoogleCredentials() ([]byte, error) {
228→	// 1. Explicit path from --credentials flag
229→	if g.credentials != "" {
230→		data, err := os.ReadFile(g.credentials)
231→		if err != nil {
232→			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
233→		}
234→		return data, nil
235→	}
236→
237→	// 2. Local file in project
238→	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", g.def.ID)
239→	if data, err := os.ReadFile(localPath); err == nil {
240→		return data, nil
241→	}
242→
243→	// 3. Bundled credentials
244→	if len(BundledCredentials) > 0 {
245→		return BundledCredentials, nil
246→	}
247→
248→	return nil, fmt.Errorf("no %s credentials found -- provide a credentials.json file", g.def.Name)
249→}
